  "verses": [
    {
      "n": 9,
      "column": "left",
      "text": "Dseedajet winnam / dsee-\ndajt tam Dseesmas / dohmajeet\nftredigi no wiſſeem winna Brih-\nnumeem.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Glawejeet winna ſwehtu\nWahrdu/ lai winnu Širdß pre-\nzajahß/ kas to KUNGU mekle.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Waizajeet pehz to KUN-\nGU un pehz winna Stiprumu/\nmekleject winna Waigu bes\nMitteſchanas.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Peeminneet winna Brih-\numuns / ko wiſſch irr darrijs /\nwinna Brihumma-Sihmes un\nwinna Muttes Teefas.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Tu Israëls/ winna Kalpa\nDsiminums / juhs Jehkaba\nBehrni/ winna Iſwehlett.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Wiſſch irr tas KUNGŚ\nmuhtu Deews/ winna Teefas eet\npahr wiſſu Semmi.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Peeminneet muhschtgi\nwinna Derribu/ to Wahrdu/ ko\nwiſſch patwehſeis lihds tuhktsto-\nschaim Auguniam.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Ko wiſſch irr darrijs ar\nAhbräänu/ un winna Swehre-\nschanu ar Ihsaäku.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un irr to Jehkabam ee-\nzehlis par Likkunu/ un Israëtam\npar muhschtgu Derribu /\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Sazzidams : Tew doh-\nschu es to Kanäana Semmi / to\nDaltu tawas eemantojamas\nTeefas.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Rad juhs maſs Pulzinsch\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un tee staigaja no n\nnas Tautaß lihds ohtrai / un\nweenas Walstibas lihds zitte\nLaudim.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Wiſſch ne fahtwe ne k\ntohs ſpaidiht / un pahrma-\nKehnimus winnu deht.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Ne aiskarreet man-\nSwaiditus/ un ne darrajt m\nneem Praweescheem taunu.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Dseedajt tam KUNG\nwiſſa Semme / fluddinajeet\ndeenas winna Peſtiſchanu.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Teizeet to Pagann St\npā winna Gohdu/ wiſſn &\nſchu Starpā winna Brihnum\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Jo tas KUNGŚ irr\nun kohti flawejańs / un bi-\njans pahr wiſſeem Deerween\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Jo wiſſi Pagann De-\nirr Elka-Deewi/ bet tas KUN-\nirr to Debbeſi darrijs.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Augſtiba un Gohds\nwinna Preekscha/ Stipruns\nLihtmiba irr winna Weetā.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Dohdeet tam KUNGŚ\njuhs Lauschu Tautas / doh-\ntam KUNGĀM Gohdu\nStiprumu.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Dohdeet tam KUNGŚ\nwinna Wahra Gohdu/ at-\nfeet Dahwanas / un nah-\npreeſſch winna Waigu / pee-\ndseet to KUNGU twehta G-\ntuma.\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Bihſteetees preeſſch n\nna wiſſa Paſaule/ir wiſſch pa\n"
    }
  ],
  "confidence": "high",
